sql:
SELECT users.user_name, teams.team_name
FROM users
INNER JOIN teams ON users.team_id = teams.team_id;

SELECT game_highlights 
FROM game_log 
WHERE home_team_id = 1 AND game_status = 'completed';

SELECT game_id, date, location
FROM game_log
ORDER BY date ASC;

SELECT *
FROM standings
WHERE team_id = (SELECT team_id FROM teams WHERE team_name = 'Boston Celtics');
